Greedy insertion with regret-based scoring considering distance increase, time window penalty, and capacity utilization, using fallback to first feasible empty assign if no positive gain found.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const REGRET_K = 3
	type cand struct {
		assignIdx int
		costInc   float64
		feasible  bool
	}
	for jj := range oris {
		orderId := total_ship + jj
		bestCand := cand{-1, 1e30, false}
		regretList := make([]cand, 0, REGRET_K)
		totalFeasible := 0
		for ai := 0; ai < MAXASSIGNS; ai++ {
			if ai >= dispatch.AssignsLen && totalFeasible > 0 && bestCand.assignIdx != -1 {
				continue
			}
			tmpAssign := dispatch.Assigns[ai]
			oldCost := tmpAssign.Cost
			added := tmpAssign.AddShip(orderId, oris[jj], dess[jj])
			if added && tmpAssign.Cost >= 0 {
				newCost := tmpAssign.Cost
				costInc := newCost - oldCost
				if costInc < 0 {
					costInc = 0
				}
				feas := true
				regretList = append(regretList, cand{ai, costInc, feas})
				totalFeasible++
				if costInc < bestCand.costInc {
					bestCand = cand{ai, costInc, true}
				}
				tmpAssign.RemoveShip(orderId)
				tmpAssign.GenRoute()
			} else {
				if added {
					tmpAssign.RemoveShip(orderId)
					tmpAssign.GenRoute()
				}
			}
		}
		var chosenIdx int = -1
		if len(regretList) >= REGRET_K {
			sort.SliceStable(regretList, func(i, j int) bool {
				return regretList[i].costInc < regretList[j].costInc
			})
			regretScore := 0.0
			for i := 1; i < REGRET_K && i < len(regretList); i++ {
				regretScore += (regretList[i].costInc - regretList[0].costInc)
			}
			if regretScore > 0 && regretList[0].feasible {
				chosenIdx = regretList[0].assignIdx
			} else {
				if bestCand.feasible && bestCand.assignIdx != -1 {
					chosenIdx = bestCand.assignIdx
				}
			}
		} else {
			if bestCand.feasible && bestCand.assignIdx != -1 {
				chosenIdx = bestCand.assignIdx
			}
		}
		if chosenIdx == -1 {
			for ai := 0; ai < MAXASSIGNS; ai++ {
				if ai >= dispatch.AssignsLen && ai >= dispatch.AssignsLen && ai < MAXASSIGNS {
					if ai >= dispatch.AssignsLen {
						if ai >= dispatch.AssignsLen {
							dispatch.AssignsLen = ai + 1
						}
					}
				}
				if dispatch.Assigns[ai].AddShip(orderId, oris[jj], dess[jj]) {
					dispatch.Assigns[ai].GenRoute()
					chosenIdx = ai
					break
				} else {
					if ai < dispatch.AssignsLen {
						dispatch.Assigns[ai].RemoveShip(orderId)
						dispatch.Assigns[ai].GenRoute()
					}
				}
			}
		} else {
			success := dispatch.Assigns[chosenIdx].AddShip(orderId, oris[jj], dess[jj])
			if success && dispatch.Assigns[chosenIdx].Cost >= 0 {
				dispatch.Assigns[chosenIdx].GenRoute()
				if chosenIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = chosenIdx + 1
				}
			} else {
				dispatch.Assigns[chosenIdx].RemoveShip(orderId)
				dispatch.Assigns[chosenIdx].GenRoute()
				for ai := 0; ai < MAXASSIGNS; ai++ {
					if ai >= dispatch.AssignsLen && ai >= dispatch.AssignsLen && ai < MAXASSIGNS {
						if ai >= dispatch.AssignsLen {
							dispatch.AssignsLen = ai + 1
						}
					}
					if dispatch.Assigns[ai].AddShip(orderId, oris[jj], dess[jj]) {
						dispatch.Assigns[ai].GenRoute()
						break
					} else {
						if ai < dispatch.AssignsLen {
							dispatch.Assigns[ai].RemoveShip(orderId)
							dispatch.Assigns[ai].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

